#include <stdio.h>
#include <stdlib.h>

int cmp_desc(const void *a, const void *b) {
    return *(int*)b - *(int*)a;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int a[3], b[3];
        scanf("%d %d %d %d %d %d", &a[0], &a[1], &a[2], &b[0], &b[1], &b[2]);
        qsort(a, 3, sizeof(int), cmp_desc);
        qsort(b, 3, sizeof(int), cmp_desc);
        int alice = a[0]*100 + a[1]*10 + a[2];
        int bob   = b[0]*100 + b[1]*10 + b[2];
        if (alice > bob) printf("Alice\n");
        else if (bob > alice) printf("Bob\n");
        else printf("Tie\n");
    }
    return 0;
}

