public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int[] a = new int[3];
            int[] b = new int[3];
            for (int i = 0; i < 3; i++) a[i] = Integer.parseInt(st.nextToken());
            for (int i = 0; i < 3; i++) b[i] = Integer.parseInt(st.nextToken());
            Arrays.sort(a);
            Arrays.sort(b);
            // sort descending by reading from end
            int alice = a[2]*100 + a[1]*10 + a[0];
            int bob   = b[2]*100 + b[1]*10 + b[0];
            if (alice > bob) sb.append("Alice\n");
            else if (bob > alice) sb.append("Bob\n");
            else sb.append("Tie\n");
        }
        System.out.print(sb.toString());
    }
}

