#!/usr/bin/env python3
import sys

def score(dice):
    d = sorted(dice, reverse=True)
    return d[0]*100 + d[1]*10 + d[2]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        a = [int(next(it)), int(next(it)), int(next(it))]
        b = [int(next(it)), int(next(it)), int(next(it))]
        alice = score(a)
        bob = score(b)
        if alice > bob:
            out.append('Alice')
        elif bob > alice:
            out.append('Bob')
        else:
            out.append('Tie')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

